return-response.set-body:
@{
        var b = (JObject)context.Variables["reqBody"];
        var filename = (string)(b["filename"] ?? "upload.bin");
        var contentType = (string)(b["contentType"] ?? "application/octet-stream");
        var safeName = System.Text.RegularExpressions.Regex.Replace(filename, "[^A-Za-z0-9._-]", "_");
        var blobName = DateTime.UtcNow.ToString("yyyyMMdd") + "/" + Guid.NewGuid().ToString("N") + "_" + safeName;
        var account = "{{storage-account-name}}";
        var key = "{{storage-account-key}}";
        var container = "citizen-uploads";
        var startTime = DateTime.UtcNow.AddMinutes(-5).ToString("yyyy-MM-ddTHH:mm:ssZ");
        var expiryTime = DateTime.UtcNow.AddMinutes(15).ToString("yyyy-MM-ddTHH:mm:ssZ");
        var permissions = "cw";
        var resource = "b";
        var canonicalizedResource = "/blob/" + account + "/" + container + "/" + blobName;
        var signedVersion = "2021-06-08";
        var signedProtocol = "https";
        var stringToSign = string.Join("\n", new string[] {
          permissions,
          startTime,
          expiryTime,
          canonicalizedResource,
          "",
          "",
          "",
          signedProtocol,
          signedVersion,
          resource,
          "",
          "",
          "",
          "",
          "",
          ""
        });
        var hmac = new System.Security.Cryptography.HMACSHA256(System.Convert.FromBase64String(key));
        var sig = System.Convert.ToBase64String(hmac.ComputeHash(System.Text.Encoding.UTF8.GetBytes(stringToSign)));
        var sas = "sv=" + signedVersion +
          "&st=" + System.Uri.EscapeDataString(startTime) +
          "&se=" + System.Uri.EscapeDataString(expiryTime) +
          "&sr=" + resource +
          "&sp=" + permissions +
          "&spr=" + signedProtocol +
          "&sig=" + System.Uri.EscapeDataString(sig);
        var blobUrl = "https://" + account + ".blob.core.windows.net/" + container + "/" + blobName;
        var uploadUrl = blobUrl + "?" + sas;
        return new JObject(
          new JProperty("uploadUrl", uploadUrl),
          new JProperty("blobUrl", blobUrl),
          new JProperty("blobName", blobName),
          new JProperty("container", container),
          new JProperty("contentType", contentType),
          new JProperty("expiresAt", expiryTime),
          new JProperty("storageAccount", account)
        ).ToString();
      }
